#include<bits/stdc++.h>
using namespace std;
int a[100010],b[100010],n;
bool check(int x)
{
    memcpy(b,a,sizeof(a));
    sort(b+1,b+x,greater<int>());
    int tmpx=x;
    for(int i=1;i<tmpx;i++)
    {
        if(b[i]<=x)
        {
            return false;
        }
        x--;
    }
    return true;
}
int main()
{
    // freopen("insert.in","r",stdin);
    // freopen("insert.out","w",stdout);
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i]=n-a[i]+1;
    }
    int l=1,r=n,best=1;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            l=mid+1;
            best=mid;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%d",n-best);
    return 0;
}
